queries.sphinxql:
create table t ( title text, category int, vec float_vector knn_type='hnsw'	hnsw_similarity='L2' model_name='sentence-transformers/all-MiniLM-L6-v2' from='title' );
insert into t (id, title, category) values (1, 'machine learning algorithms and neural networks', 1);
insert into t (id, title, category) values (2, 'deep learning for computer vision applications', 1);
insert into t (id, title, category) values (3, 'natural language processing with transformers', 1);
insert into t (id, title, category) values (4, 'cooking italian pasta recipes at home', 2);
insert into t (id, title, category) values (5, 'travel guide to european destinations', 2);
insert into t (id, title, category) values (6, 'football match results and sports news', 2);
flush ramchunk t;

select id, hybrid_score() from t where hybrid_match('machine learning', vec);
select id, hybrid_score() from t where hybrid_match('machine learning');
select id, hybrid_score() from t where hybrid_match('machine learning', vec, {k=3}) option rank_constant=10;
select id, category, hybrid_score() from t where hybrid_match('machine learning', vec) and category=1;
select id, hybrid_score() from t where hybrid_match('xyznonexistent', vec);
select id, weight(), knn_dist(), hybrid_score() from t where match('machine learning') and knn(vec, 3, 'machine learning') option fusion_method='rrf';
select id, hybrid_score() hs from t where hybrid_match('neural networks', vec) order by hs desc;
select id, knn_dist() from t where hybrid_match('neural networks', vec) order by knn_dist() asc;
select id, weight() w from t where hybrid_match('neural networks', vec) order by w desc;
drop table t;
